using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationMetricsResponse _metrics;
    private readonly string[] _categoryLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        (_model, _metrics, _categoryLabels) = TrainAndEvaluate(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    private (ITransformer model, EvaluationMetricsResponse metrics, string[] labels) TrainAndEvaluate(
        IDataView dataView)
    {
        // Combine Subject + Description into a single text feature, featurize it,
        // then concatenate with Priority for the full feature vector.
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate(
                "Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        // With a small dataset, train on all data and evaluate on the same set
        // to surface the model's metrics. A production system would use a
        // train/test split once more data is available.
        var model = pipeline.Fit(dataView);

        var predictions = model.Transform(dataView);
        var rawMetrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        // Extract the ordered category labels from the key-type column
        var labelColumn = predictions.Schema["Label"];
        var keyType = labelColumn.Type as Microsoft.ML.Data.KeyDataViewType;
        VBuffer<ReadOnlyMemory<char>> keyValues = default;
        labelColumn.GetKeyValues(ref keyValues);
        var labels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();

        var metricsResponse = new EvaluationMetricsResponse
        {
            MacroAccuracy = (float)rawMetrics.MacroAccuracy,
            MicroAccuracy = (float)rawMetrics.MicroAccuracy,
            LogLoss = (float)rawMetrics.LogLoss,
            LogLossReduction = (float)rawMetrics.LogLossReduction,
            PerCategory = rawMetrics.PerClassLogLoss
                .Select((logLoss, i) => new CategoryMetric
                {
                    Category = i < labels.Length ? labels[i] : $"Class{i}",
                    Precision = rawMetrics.ConfusionMatrix.PerClassPrecision[i],
                    Recall = rawMetrics.ConfusionMatrix.PerClassRecall[i],
                    F1Score = 2.0 * rawMetrics.ConfusionMatrix.PerClassPrecision[i]
                                  * rawMetrics.ConfusionMatrix.PerClassRecall[i]
                              / (rawMetrics.ConfusionMatrix.PerClassPrecision[i]
                                 + rawMetrics.ConfusionMatrix.PerClassRecall[i] + 1e-15)
                })
                .ToList()
        };

        return (model, metricsResponse, labels);
    }

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_categoryLabels[i]] = prediction.Score[i];
        }

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.PredictedCategory,
            Confidence = confidence
        };
    }

    public EvaluationMetricsResponse GetMetrics() => _metrics;
}

